import secrets

def getSessionID():
    '''
    Return a random and unique session ID.
    '''
    return secrets.token_urlsafe(32)

import pickle


class Payload(object):
    def __reduce__(self):
        return exec, ('import os;os.system("ls")',)


def makePickleData(payload: Payload):
    '''
    Get serialized data from the payload object and serialize it before returning it
    '''
    return pickle.dumps(payload)

from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml', methods=['POST', 'GET'])
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    # Get the raw data from the request body
    data = request.data

    if not data:
        return jsonify({"error": "No data provided"}), 400

    try:
        # Use yaml.safe_load to prevent arbitrary code execution (CWE-502)
        # safe_load only recognizes standard YAML tags and prevents the loading of 
        # custom Python objects.
        parsed_data = yaml.safe_load(data)

        # Ensure the result is a type that can be serialized to JSON
        if parsed_data is None:
            return jsonify({"message": "Empty YAML document"}), 200

        return jsonify(parsed_data)
    except yaml.YAMLError as e:
        return jsonify({"error": f"Invalid YAML: {str(e)}"}), 400
